ruleContent.content:
@js:
(function(){
    var count = 60;
    var dateStr = "202507"; 

    // 提取目录传来的参数
    var cParam = baseUrl.match(/count=(\d+)/);
    if(cParam) count = parseInt(cParam[1]);

    var dParam = baseUrl.match(/date=(\d+)/);
    if(dParam) dateStr = dParam[1];

    var idMatch = baseUrl.match(/\/comic\/(\d+)\/(\d+)/);
    if(!idMatch) return "解析链接 ID 失败";
    var comicId = idMatch[1];
    var chapterId = idMatch[2];

    // 构建 CDN 基础路径
    var imgBase = "https://fm.mwtt.cc/" + dateStr + "/" + comicId + "/" + chapterId;

    var ua = "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/116.0.0.0 Mobile Safari/537.36";
    var cleanRef = baseUrl.split('?')[0]; 
    var header = ',{"headers":{"Referer":"' + cleanRef + '","User-Agent":"' + ua + '"}}';

    var res = [];
    // 循环生成图片，多生成5张做容错
    for(var i = 0; i <= count + 5; i++) {
        res.push('<img src="' + imgBase + '/' + i + '.jpg' + header + '">');
    }

    return res.join("\n");
})();

ruleToc.chapterUrl:
@js:
(function(){
    var url = java.getString("@href");
    var metaText = java.getString(".chapter-meta@text"); 

    var countMatch = metaText.match(/(\d+)\s*图/);
    var count = countMatch ? countMatch[1] : "50";

    var dateMatch = metaText.match(/(\d{4})-(\d{2})/);
    var date = dateMatch ? (dateMatch[1] + dateMatch[2]) : "202504";

    return url + "?count=" + count + "&date=" + date;
})();
